<template>
  <PreHeader />
  <HeaderMenu />

  <div class="content">
    <div class="card-program-header">
      <WaveContainer :title="'Game luyện gõ phím đơn'" description="" />
    </div>

    <div class="card-program-body">
      <iframe
        :src="'/quizes/' + embedLink"
        width="100%"
        height="800px"
      ></iframe>
    </div>
  </div>

  <FooterMenu />
</template>

<script>
import gameData from "@/assets/data/game.json";
import PreHeader from "@/components/PreHeader.vue";
import HeaderMenu from "@/components/HeaderMenu.vue";
import FooterMenu from "@/components/FooterMenu.vue";

const urlParams = new URLSearchParams(window.location.search);
let idGame = urlParams.get("id");
if (idGame == null) idGame = -1;
let currentGame = gameData.find((game) => game.id == idGame);
let contentLink = currentGame.contentdir;

export default {
  name: "App",
  components: {
    PreHeader,
    HeaderMenu,
    FooterMenu,
  },
  data() {
    return {
      embedLink: contentLink,
    };
  },
};
</script>

<style>
@import "@/assets/css/style.css";
#app {
  font-family: Avenir, Helvetica, Arial, sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-align: center;
  color: #2c3e50;
}
</style>
